
INSERT INTO countries (id, name_ru, name_en, code)
SELECT gen_random_uuid(), 'Беларусь', 'Belarus', 'BY'
WHERE NOT EXISTS (SELECT 1 FROM countries WHERE code = 'BY');

INSERT INTO cities (id, country_id, name_ru, name_en, region, lat, lon)
SELECT gen_random_uuid(), c.id, 'Минск', 'Minsk', 'Минская область', 53.9006, 27.5590
FROM countries c
WHERE c.code = 'BY'
  AND NOT EXISTS (SELECT 1 FROM cities WHERE name_en = 'Minsk');


